import React from 'react'
import { css } from '@linaria/core'
import { ControlTarget } from '@fs/zion-icon'
import { createPortal } from 'react-dom'
import { i18n } from '@fs/zion-locale'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'

import { useChildrenBounds } from '../../../../components/Map/hooks/useChildrenBounds'
import useMap from '../../shared/hooks/useMap'
import useLibraries from '../hooks/useLibraries'
import useAddControlToMap from '../hooks/useAddControlToMap'

const buttonClassName = css`
  background: ${rawDayColors.gray['00']};
  border: 0;
  box-shadow: rgb(0 0 0 / 30%) 0px 1px 4px -1px;
  color: #666666;
  margin: 10px;
  padding: 8px;

  &:hover {
    color: #333333;
  }
`

const LARGEST_MARKER_SIZE_PX = 64

export default function ResetViewControl() {
  const { googleApiKey, initialLatitude, initialLongitude, initialZoom, map, nonInteractive, zoomPan } = useMap()
  const { libraries } = useLibraries({ googleApiKey })
  const childrenBounds = useChildrenBounds()
  const controlRef = useAddControlToMap({ position: libraries?.core.ControlPosition.BLOCK_START_INLINE_END })

  if (nonInteractive) {
    return null
  }

  function handleOnClick() {
    if (childrenBounds.bounds) {
      map.fitBounds(childrenBounds.bounds, LARGEST_MARKER_SIZE_PX)
    } else if (childrenBounds.optimalZoom !== undefined && childrenBounds.centroidLocation) {
      zoomPan({
        latitude: childrenBounds.centroidLocation.latitude,
        longitude: childrenBounds.centroidLocation.longitude,
        zoom: childrenBounds.optimalZoom,
      })
    } else {
      zoomPan({
        latitude: initialLatitude,
        longitude: initialLongitude,
        zoom: initialZoom,
      })
    }
  }

  return (
    <>
      {createPortal(
        <button
          aria-label={i18n.t('map.reset-view.action', 'Reset view')}
          className={buttonClassName}
          onClick={handleOnClick}
          title={i18n.t('map.reset-view.action', 'Reset view')}
          type="button"
        >
          <ControlTarget />
        </button>,
        controlRef.current
      )}
    </>
  )
}
