import { useEffect, useRef } from 'react'

import useMap from '../../shared/hooks/useMap'
import useLibraries from './useLibraries'

export default function useAddControlToMap({ position }) {
  const controlRef = useRef()
  const { googleApiKey, map } = useMap()
  const { libraries } = useLibraries({ googleApiKey })

  if (!controlRef.current) {
    controlRef.current = document.createElement('div')
  }

  useEffect(() => {
    if (!map || !libraries || !position) {
      return undefined
    }

    const customControls = map.controls[position]

    customControls.push(controlRef.current)

    return () => {
      const controlIndexCurrent = customControls?.getArray().indexOf(controlRef.current)

      if (controlIndexCurrent > -1) {
        customControls?.removeAt(controlIndexCurrent)
      }
    }
  }, [libraries, map, position])

  // Cleanup the control element on unmount
  useEffect(() => {
    return () => {
      if (controlRef.current) {
        controlRef.current.remove()
      }

      controlRef.current = null
    }
  }, [])

  return controlRef
}
