import React, { forwardRef, useCallback, useEffect, useImperativeHandle, useMemo, useRef, useState } from 'react'
import { css } from '@linaria/core'
import { i18n } from '@fs/zion-locale'
import { NoticeLoading } from '@fs/zion-icon'
import { Alert } from '@fs/zion-ui'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'
import { useEvent } from '@fs/zion-frontend-friends'
import PropTypes from 'prop-types'

import { createPortal } from 'react-dom'
import { useChildrenBounds, useChildrenBoundsApi } from '../../../components/Map/hooks/useChildrenBounds'
import useLibraries from './hooks/useLibraries'
import { SharedPopperProvider } from '../shared/hooks/useSharedPopper'
import { MapProvider } from '../shared/hooks/useMap'
import { ResetViewControl, UserLocationControl } from './controls'
import Center from '../shared/Center'
import customMapTypeIds from './customMapTypeIds'
import useThrottle from '../shared/hooks/useThrottle'
import FullscreenControl from '../shared/controls/FullscreenControl'

const LARGEST_MARKER_SIZE_PX = 64
const BOUNDS_CHANGED_THROTTLE_DELAY_MS = 300
const POPPER_UPDATE_DURATION_MS = 500
const POPPER_UPDATE_INTERVAL_MS = 10
const DOUBLE_CLICK_DELAY = 250

const mapContainerClassName = css`
  block-size: 100%;
  inline-size: 100%;
  overflow: hidden;
  position: relative;
`

const mapClassName = css`
  block-size: 100%;
  inline-size: 100%;

  // Note: zion-ui removes the default outline on focus for buttons; this adds it back.
  button:active,
  button:focus,
  button:focus-visible {
    outline: auto 2px Highlight;
    outline: -webkit-focus-ring-color auto 1px;
  }
`

function normalizeZoomLevels({ minZoom, maxZoom }) {
  // Ensure minZoom is always less than maxZoom
  let normalizedMinZoom = minZoom
  let normalizedMaxZoom = maxZoom

  if (typeof minZoom === 'number' && typeof maxZoom === 'number' && minZoom >= maxZoom) {
    normalizedMinZoom = maxZoom - 1
    normalizedMaxZoom = maxZoom
  }

  return { normalizedMinZoom, normalizedMaxZoom }
}

function createMapOptions({
  bounds,
  controlPosition,
  gestureHandling,
  googleMapId,
  hideMapTypeControl,
  initialLatitude,
  initialLongitude,
  initialMapTypeId,
  initialZoom,
  nonInteractive,
  normalizedMaxZoom,
  normalizedMinZoom,
  onClick,
}) {
  let draggableCursor = 'grab'
  let draggingCursor = 'grabbing'

  if (nonInteractive) {
    draggableCursor = 'default'
    draggingCursor = 'default'
  } else if (onClick) {
    draggableCursor = 'pointer'
  }

  return {
    backgroundColor: rawDayColors.gray['00'],
    cameraControl: false, // If we add this later use: !nonInteractive,
    center: {
      lat: initialLatitude,
      lng: initialLongitude,
    },
    disableDoubleClickZoom: nonInteractive,
    draggableCursor,
    draggingCursor,
    // Note: Google's fullscreen control makes a Google Map internal element fullscreen.
    // This makes it much more difficult to show poppers.  We add our own control and make
    // the entire wrapping element fullscreen instead.
    fullscreenControl: false,
    gestureHandling,
    isFractionalZoomEnabled: true,
    keyboardShortcuts: !nonInteractive,
    mapTypeId: initialMapTypeId === 'roadmap' ? 'clean' : initialMapTypeId,
    mapTypeControl: initialMapTypeId !== 'blank' && !nonInteractive && !hideMapTypeControl,
    maxZoom: normalizedMaxZoom,
    minZoom: normalizedMinZoom,
    // The `mapId` is required in order to use `AdvancedMarkerElement`.
    // It can be replaced with a Map ID from the Google Maps Cloud console.
    // See: https://developers.google.com/maps/documentation/javascript/map-ids/get-map-id
    mapId: googleMapId || 'DEMO_MAP_ID',
    restriction: bounds ? { latLngBounds: bounds, strictBounds: true } : undefined,
    rotateControl: false,
    scaleControl: false,
    streetViewControl: false,
    tilt: 0,
    zoom: initialZoom,
    zoomControl: !nonInteractive,
    zoomControlOptions: {
      position: controlPosition,
    },
  }
}

function useMapCreation({
  initialOptionsRef,
  libraries,
  mapRef,
  onChange,
  onReady,
  setLoading,
  setMap,
  sharedPopperRef,
}) {
  const mapCreatedRef = useRef()

  // Stable callbacks that never recreate - RFC pattern
  const stableOnChange = useEvent(onChange)
  const stableOnReady = useEvent(onReady)

  useEffect(() => {
    let mapTypeIdChangedListener

    if (libraries && !mapCreatedRef.current) {
      mapCreatedRef.current = true

      setLoading(true)

      const newMap = new libraries.maps.Map(mapRef.current, initialOptionsRef.current)

      mapTypeIdChangedListener = customMapTypeIds.setup({ libraries, map: newMap })

      // The tilesloaded event acts as a "ready" event for the map since
      // Google Maps doesn't have a built-in onReady.
      libraries.core.event.addListenerOnce(newMap, 'tilesloaded', () => {
        setMap(newMap)
        setLoading(false)
        stableOnChange?.({ closeOverlay: () => sharedPopperRef.current?.closeOverlay?.() })
        stableOnReady?.()
      })
    }

    return () => {
      if (mapTypeIdChangedListener) {
        libraries.core.event.removeListener(mapTypeIdChangedListener)
      }

      mapCreatedRef.current = null
    }
  }, [libraries, initialOptionsRef, mapRef, setMap, setLoading, sharedPopperRef, stableOnChange, stableOnReady])
}

function useBoundsChangedListener({ libraries, map, onBoundsChanged, onBoundsChangedCallbacksRef }) {
  const boundsChanged = useCallback(() => {
    const currentCenter = map.getCenter()
    const currentBounds = map.getBounds()
    const currentZoom = map.getZoom()

    const northEast = currentBounds?.getNorthEast()
    const southWest = currentBounds?.getSouthWest()

    const args = {
      center: { latitude: currentCenter.lat(), longitude: currentCenter.lng() },
      east: northEast?.lng(),
      north: northEast?.lat(),
      south: southWest?.lat(),
      west: southWest?.lng(),
      zoom: currentZoom,
    }

    onBoundsChangedCallbacksRef.current.forEach(({ callback }) => callback(args))
    onBoundsChanged?.(args)
  }, [map, onBoundsChanged, onBoundsChangedCallbacksRef])

  const throttledBoundsChanged = useThrottle(BOUNDS_CHANGED_THROTTLE_DELAY_MS, boundsChanged)

  // Listen for bounds changes
  useEffect(() => {
    let boundsChangedListener

    if (map && (typeof onBoundsChanged === 'function' || onBoundsChangedCallbacksRef.current.length > 0)) {
      boundsChangedListener = libraries.core.event.addListener(map, 'bounds_changed', throttledBoundsChanged)
    }

    return () => {
      if (boundsChangedListener) {
        libraries.core.event.removeListener(boundsChangedListener)
      }
    }
  }, [libraries, map, onBoundsChanged, onBoundsChangedCallbacksRef, throttledBoundsChanged])
}

function useZoomChangedListener({ libraries, map, onZoomChangedCallbacksRef, zoomRef }) {
  useEffect(() => {
    let zoomChangedListener

    if (map && onZoomChangedCallbacksRef.current.length > 0) {
      zoomChangedListener = libraries.core.event.addListener(map, 'zoom_changed', () => {
        const currentZoom = map.getZoom()

        if (currentZoom !== zoomRef.current) {
          const currentBounds = map.getBounds()
          const currentCenter = map.getCenter()

          const northEast = currentBounds?.getNorthEast()
          const southWest = currentBounds?.getSouthWest()

          zoomRef.current = currentZoom

          onZoomChangedCallbacksRef.current.forEach(({ callback }) =>
            callback({
              center: { latitude: currentCenter.lat(), longitude: currentCenter.lng() },
              east: northEast?.lng(),
              north: northEast?.lat(),
              south: southWest?.lat(),
              west: southWest?.lng(),
              zoom: currentZoom,
            })
          )
        }
      })
    }

    return () => {
      if (zoomChangedListener) {
        libraries.core.event.removeListener(zoomChangedListener)
      }
    }
  }, [libraries, map, onZoomChangedCallbacksRef, zoomRef])
}

function useMapClickListener({ libraries, map, onClick, skipNextClickRef }) {
  const clickTimerRef = useRef()
  const onClickRef = useRef(onClick)

  useEffect(() => {
    onClickRef.current = onClick
  }, [onClick])

  useEffect(() => {
    if (!map || !libraries) {
      return undefined
    }

    // Ignore double clicks
    const doubleClickListener = libraries.core.event.addListener(map, 'dblclick', () => {
      // Clear any pending single click
      if (clickTimerRef.current) {
        clearTimeout(clickTimerRef.current)
        clickTimerRef.current = null
      }
    })

    const clickListener = libraries.core.event.addListener(map, 'click', (event) => {
      if (skipNextClickRef.current) {
        skipNextClickRef.current = false

        return
      }

      // Delay single click to wait for potential double click
      clickTimerRef.current = setTimeout(() => {
        if (onClickRef.current) {
          onClickRef.current({
            position: {
              latitude: event.latLng.lat(),
              longitude: event.latLng.lng(),
            },
          })
        }

        clickTimerRef.current = null
      }, DOUBLE_CLICK_DELAY)
    })

    return () => {
      if (clickTimerRef.current) {
        clearTimeout(clickTimerRef.current)
      }

      libraries.core.event.removeListener(clickListener)
      libraries.core.event.removeListener(doubleClickListener)
    }
  }, [libraries, map, skipNextClickRef])
}

function useMapOptions({ map, options }) {
  // NOTE: This must come before `Fit the map to the children bounds` in order for the children bounds to work correctly.
  // Update the map options when they change
  useEffect(() => {
    if (map) {
      map.setOptions(options)
    }
  }, [map, options])
}

function useMapViewFitting({ childrenBounds, childrenBoundsApi, map, options }) {
  // NOTE: This must come after `Update the map options` in order for the options to be set correctly.
  // Fit the map to the children bounds or center on the initial location.
  useEffect(() => {
    if (!map) {
      return
    }

    if (childrenBoundsApi.skipNextFitToChildrenRef.current) {
      childrenBoundsApi.skipNextFitToChildrenRef.current = false
      return
    }

    if (childrenBounds.bounds) {
      map.fitBounds(childrenBounds.bounds, LARGEST_MARKER_SIZE_PX)
    } else if (childrenBounds.optimalZoom !== undefined && childrenBounds.centroidLocation) {
      map.setZoom(childrenBounds.optimalZoom)
      map.panTo({
        lat: childrenBounds.centroidLocation.latitude,
        lng: childrenBounds.centroidLocation.longitude,
      })
    } else {
      map.setOptions({
        center: options.center,
        zoom: options.zoom,
      })
    }
  }, [childrenBounds, childrenBoundsApi, map, options])
}

function useFullscreenControl({ libraries, map, fullscreenControlRef }) {
  // Add the fullscreen control to the map
  // This is needed to ensure the proper tab order for A11Y.
  useEffect(() => {
    if (!map || !libraries) {
      return undefined
    }

    const customControls = map.controls[libraries.core.ControlPosition.INLINE_END_BLOCK_START]
    const controlElement = fullscreenControlRef.current

    customControls.push(controlElement)

    return () => {
      const controlIndexCurrent = customControls?.getArray().indexOf(controlElement)

      if (controlIndexCurrent > -1) {
        customControls?.removeAt(controlIndexCurrent)
      }
    }
  }, [libraries, map, fullscreenControlRef])
}

function useMapIdleState({ libraries, map, isIdle }) {
  // Track map idle state
  useEffect(() => {
    if (!map || !libraries?.core) {
      return undefined
    }

    function handleIdle() {
      isIdle.current = true
    }

    function handleNotIdle() {
      isIdle.current = false
    }

    const listeners = [
      libraries.core.event.addListener(map, 'bounds_changed', handleNotIdle),
      libraries.core.event.addListener(map, 'center_changed', handleNotIdle),
      libraries.core.event.addListener(map, 'zoom_changed', handleNotIdle),
      libraries.core.event.addListener(map, 'idle', handleIdle),
    ]

    return () => {
      listeners.forEach((listener) => {
        libraries.core.event.removeListener(listener)
      })
    }
  }, [map, libraries, isIdle])
}

function createBoundsCallbackData({ map }) {
  const currentBounds = map.getBounds()
  const currentCenter = map.getCenter()
  const currentZoom = map.getZoom()
  const northEast = currentBounds?.getNorthEast()
  const southWest = currentBounds?.getSouthWest()

  return {
    center: { latitude: currentCenter.lat(), longitude: currentCenter.lng() },
    east: northEast?.lng(),
    north: northEast?.lat(),
    south: southWest?.lat(),
    west: southWest?.lng(),
    zoom: currentZoom,
  }
}

function handleZoomPan({ bounds, latitude, longitude, map, zoom }) {
  if (bounds) {
    map.fitBounds(bounds, LARGEST_MARKER_SIZE_PX)
  } else if (zoom) {
    map.setZoom(zoom)
  }

  if (
    typeof latitude === 'number' &&
    !Number.isNaN(latitude) &&
    typeof longitude === 'number' &&
    !Number.isNaN(longitude)
  ) {
    map.panTo({ lat: latitude, lng: longitude })
  }
}

const GoogleMap = forwardRef(
  (
    {
      bounds,
      children,
      googleApiKey,
      googleMapId,
      hideFullscreenControl,
      hideMapTypeControl,
      initialLatitude,
      initialLongitude,
      initialMapTypeId,
      initialZoom,
      maxZoom,
      minZoom,
      nonInteractive,
      onBoundsChanged,
      onChange,
      onClick,
      onInfoClosed,
      onReady,
      parentScrolls,
      testId = 'google-map',
      userLocation,
    },
    ref
  ) => {
    const mapRef = useRef()
    const [map, setMap] = useState()
    const [loading, setLoading] = useState(true)
    const { error, libraries } = useLibraries({ googleApiKey })
    const childrenBounds = useChildrenBounds()
    const childrenBoundsApi = useChildrenBoundsApi()
    const onBoundsChangedCallbacksRef = useRef([])
    const onZoomChangedCallbacksRef = useRef([])
    const zoomRef = useRef(initialZoom)
    const popperUpdateHandlerListenersRef = useRef([])
    const fullscreenContainerRef = useRef()
    const fullscreenControlRef = useRef()
    const isIdle = useRef(true)
    const sharedPopperRef = useRef()
    const skipNextClickRef = useRef(false)

    useImperativeHandle(
      ref,
      () => ({
        closeOverlay: () => sharedPopperRef.current?.closeOverlay?.(),
      }),
      []
    )

    const controlPosition = libraries?.core.ControlPosition.BLOCK_START_INLINE_END

    const { normalizedMinZoom, normalizedMaxZoom } = normalizeZoomLevels({ minZoom, maxZoom })

    const gestureHandling = useMemo(() => {
      if (nonInteractive) return 'none'
      if (parentScrolls) return 'cooperative'

      return 'greedy'
    }, [nonInteractive, parentScrolls])

    const isPrimarilyTouchscreen = typeof window !== 'undefined' && window.matchMedia('(pointer: coarse)').matches

    const options = useMemo(
      () =>
        createMapOptions({
          bounds,
          controlPosition,
          gestureHandling,
          googleMapId,
          hideMapTypeControl,
          initialLatitude,
          initialLongitude,
          initialMapTypeId,
          initialZoom,
          nonInteractive,
          normalizedMaxZoom,
          normalizedMinZoom,
          onClick,
        }),
      [
        bounds,
        controlPosition,
        gestureHandling,
        googleMapId,
        hideMapTypeControl,
        initialLatitude,
        initialLongitude,
        initialMapTypeId,
        initialZoom,
        nonInteractive,
        normalizedMaxZoom,
        normalizedMinZoom,
        onClick,
      ]
    )
    const initialOptionsRef = useRef(options)

    if (!fullscreenControlRef.current) {
      fullscreenControlRef.current = document.createElement('div')
    }

    useMapCreation({ initialOptionsRef, libraries, mapRef, onChange, onReady, setLoading, setMap, sharedPopperRef })
    useBoundsChangedListener({ libraries, map, onBoundsChanged, onBoundsChangedCallbacksRef })
    useZoomChangedListener({ libraries, map, onZoomChangedCallbacksRef, zoomRef })
    useMapClickListener({ libraries, map, onClick, skipNextClickRef })
    useMapOptions({ map, options })
    useMapViewFitting({ childrenBounds, childrenBoundsApi, map, options })
    useFullscreenControl({ libraries, map, fullscreenControlRef })
    useMapIdleState({ libraries, map, isIdle })

    const getCurrentZoom = useCallback(() => {
      if (!map) {
        return null
      }

      return map.getZoom()
    }, [map])

    const onBoundsChangedAdd = useCallback(
      ({ callback, id }) => {
        onBoundsChangedCallbacksRef.current.push({ callback, id })

        if (map) {
          callback(createBoundsCallbackData({ map }))
        }
      },
      [map]
    )

    const onBoundsChangedRemove = useCallback(({ id }) => {
      onBoundsChangedCallbacksRef.current = onBoundsChangedCallbacksRef.current.filter(
        ({ id: currentId }) => currentId !== id
      )
    }, [])

    const onBoundsChangedMemo = useMemo(
      () => ({
        add: onBoundsChangedAdd,
        remove: onBoundsChangedRemove,
      }),
      [onBoundsChangedAdd, onBoundsChangedRemove]
    )

    const onZoomChangedAdd = useCallback(({ callback, id }) => {
      onZoomChangedCallbacksRef.current.push({ callback, id })
    }, [])

    const onZoomChangedRemove = useCallback(({ id }) => {
      onZoomChangedCallbacksRef.current = onZoomChangedCallbacksRef.current.filter(
        ({ id: currentId }) => currentId !== id
      )
    }, [])

    const onZoomChangedMemo = useMemo(
      () => ({
        add: onZoomChangedAdd,
        remove: onZoomChangedRemove,
      }),
      [onZoomChangedAdd, onZoomChangedRemove]
    )

    const whenIdle = useCallback(
      ({ callback }) => {
        return new Promise((resolve) => {
          if (isIdle.current) {
            callback()
            resolve()
          } else if (map && libraries) {
            libraries.core.event.addListenerOnce(map, 'idle', () => {
              callback()
              resolve()
            })
          }
        })
      },
      [libraries, map]
    )

    const zoomPan = useCallback(
      ({ bounds: zoomPanBounds, latitude, longitude, zoom }) => {
        if (!map) {
          return
        }

        handleZoomPan({ bounds: zoomPanBounds, latitude, longitude, map, zoom })
      },
      [map]
    )

    const updateHandlerAdd = useCallback(
      (callback) => {
        if (!libraries || !map) {
          return
        }

        // Note: Google Maps invokes the events before the map is fully settled during animations or other changes.
        // This ensures that the popper is updated during these changes.
        const updateDuringChange = () => {
          callback()

          const start = Date.now()
          const interval = setInterval(() => {
            callback()
            if (Date.now() - start >= POPPER_UPDATE_DURATION_MS) {
              clearInterval(interval)
            }
          }, POPPER_UPDATE_INTERVAL_MS)
        }

        popperUpdateHandlerListenersRef.current.push(
          libraries.core.event.addListener(map, 'center_changed', updateDuringChange),
          libraries.core.event.addListener(map, 'zoom_changed', updateDuringChange),
          libraries.core.event.addListener(map, 'idle', updateDuringChange)
        )
      },
      [libraries, map]
    )

    const updateHandlerRemove = useCallback(() => {
      if (!libraries) {
        return
      }

      popperUpdateHandlerListenersRef.current.forEach((listener) => {
        libraries.core.event.removeListener(listener)
      })

      popperUpdateHandlerListenersRef.current = []
    }, [libraries])

    const updateHandlerMemo = useMemo(
      () => ({
        add: updateHandlerAdd,
        remove: updateHandlerRemove,
      }),
      [updateHandlerAdd, updateHandlerRemove]
    )

    return (
      <div className={mapContainerClassName} ref={fullscreenContainerRef}>
        {error && (
          <Center>
            <Alert type="error">{i18n.t('map.google-api.error', 'Error: Google Maps API failed to load.')}</Alert>
          </Center>
        )}
        {loading && (
          <Center>
            <NoticeLoading color={rawDayColors.gray[100]} size="lg" />
          </Center>
        )}
        <div className={mapClassName} data-testid={testId} ref={mapRef} />
        <MapProvider
          fullscreenContainer={fullscreenContainerRef.current}
          gestureHandling={gestureHandling}
          getCurrentZoom={getCurrentZoom}
          googleApiKey={googleApiKey}
          initialLatitude={initialLatitude}
          initialLongitude={initialLongitude}
          initialZoom={initialZoom}
          map={map}
          mapContainer={mapRef}
          maxZoom={normalizedMaxZoom}
          nonInteractive={nonInteractive}
          onBoundsChanged={onBoundsChangedMemo}
          onZoomChanged={onZoomChangedMemo}
          skipNextClickRef={skipNextClickRef}
          whenIdle={whenIdle}
          zoomPan={zoomPan}
        >
          <SharedPopperProvider onInfoClosed={onInfoClosed} updateHandler={updateHandlerMemo} ref={sharedPopperRef}>
            <ResetViewControl />
            {userLocation && <UserLocationControl />}
            {!hideFullscreenControl && !isPrimarilyTouchscreen && (
              // The fragment is needed to prevent an `Invalid prop children` error.
              <>{createPortal(<FullscreenControl />, fullscreenControlRef.current)}</>
            )}
            {children}
          </SharedPopperProvider>
        </MapProvider>
      </div>
    )
  }
)

GoogleMap.displayName = 'GoogleMap'

export default GoogleMap

GoogleMap.propTypes = {
  bounds: PropTypes.shape({
    east: PropTypes.number.isRequired,
    north: PropTypes.number.isRequired,
    south: PropTypes.number.isRequired,
    west: PropTypes.number.isRequired,
  }),
  children: PropTypes.node,
  googleApiKey: PropTypes.string,
  googleMapId: PropTypes.string,
  hideFullscreenControl: PropTypes.bool,
  hideMapTypeControl: PropTypes.bool,
  initialLatitude: PropTypes.number.isRequired,
  initialLongitude: PropTypes.number.isRequired,
  initialMapTypeId: PropTypes.string,
  initialZoom: PropTypes.number,
  maxZoom: PropTypes.number,
  minZoom: PropTypes.number,
  nonInteractive: PropTypes.bool,
  onBoundsChanged: PropTypes.func,
  onChange: PropTypes.func,
  onClick: PropTypes.func,
  onInfoClosed: PropTypes.func,
  onReady: PropTypes.func,
  parentScrolls: PropTypes.bool,
  testId: PropTypes.string,
  userLocation: PropTypes.bool,
}
