import React, { useState } from 'react'
import { css } from '@linaria/core'
import { createPortal } from 'react-dom'
import { i18n } from '@fs/zion-locale'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'
import { Person } from '@fs/zion-icon'

import useMap from '../../shared/hooks/useMap'
import useLibraries from '../hooks/useLibraries'
import useAddControlToMap from '../hooks/useAddControlToMap'
import UserLocation from '../../shared/controls/UserLocation'

const buttonClassName = css`
  background: ${rawDayColors.gray['00']};
  border: 0;
  box-shadow: rgb(0 0 0 / 30%) 0px 1px 4px -1px;
  color: #666666;
  margin: 10px;
  padding: 8px;

  &:hover {
    color: #333333;
  }
`

export default function UserLocationControl() {
  const { googleApiKey, nonInteractive } = useMap()
  const { libraries } = useLibraries({ googleApiKey })
  const [userLocationClickHandler, setUserLocationClickHandler] = useState()
  const controlRef = useAddControlToMap({ position: libraries?.core.ControlPosition.BLOCK_START_INLINE_END })

  if (nonInteractive) {
    return null
  }

  function handleOnClick() {
    userLocationClickHandler?.()
  }

  return (
    <>
      {createPortal(
        <button
          aria-label={i18n.t('map.your-location.action', 'Your location')}
          className={buttonClassName}
          onClick={handleOnClick}
          title={i18n.t('map.your-location.action', 'Your location')}
          type="button"
        >
          <Person />
        </button>,
        controlRef.current
      )}
      <UserLocation setClickHandler={setUserLocationClickHandler} />
    </>
  )
}
