function setup({ libraries, map }) {
  // Setting styles on the front-end (as apposed to Cloud-based maps styling)
  // is not officially supported when using a `mapId`
  // (a `mapId` is required to use `AdvancedMarkerElement`).
  // This workaround; however, does work for some cases but gives a console warning.
  // This console warning can be ignored.
  //
  // The workaround only works for `roadmap` (vector) maps and
  // not `satellite` or `terrain` (raster) maps.
  //
  // See:
  // https://stackoverflow.com/a/78583011/2344083
  // https://stackoverflow.com/q/77127884/2344083
  if (!map.mapTypes.blank) {
    const blankStyles = new libraries.maps.StyledMapType([{ elementType: 'all', stylers: [{ visibility: 'off' }] }])
    map.mapTypes.set('blank', blankStyles)
  }

  if (!map.mapTypes.clean) {
    const cleanStyles = new libraries.maps.StyledMapType([
      { featureType: 'landscape', elementType: 'labels', stylers: [{ visibility: 'off' }] },
      { featureType: 'poi', elementType: 'labels', stylers: [{ visibility: 'off' }] },
      { featureType: 'transit', elementType: 'labels', stylers: [{ visibility: 'off' }] },
    ])
    map.mapTypes.set('clean', cleanStyles)
  }

  // Return the listener so that it can be removed later.
  return libraries.core.event.addListener(map, 'maptypeid_changed', () => {
    if (map.getMapTypeId() === 'roadmap') {
      map.setMapTypeId('clean')
    }
  })
}

export default {
  setup,
}
